'use client'
import { cn } from '@cascivo/core'
import { createContext, type InputHTMLAttributes, type ReactNode } from 'react'
import styles from './radio-card.module.css'

interface RadioCardCtx {
  name: string
  value?: string | undefined
  defaultValue?: string | undefined
  onValueChange?: ((value: string) => void) | undefined
}

const Ctx = createContext<RadioCardCtx>({ name: '' })

export interface RadioCardGroupProps {
  name: string
  label: string
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  children: ReactNode
  className?: string | undefined
}

export function RadioCardGroup({
  name,
  label,
  value,
  defaultValue,
  onValueChange,
  children,
  className,
}: RadioCardGroupProps) {
  return (
    <Ctx.Provider value={{ name, value, defaultValue, onValueChange }}>
      <div role="radiogroup" aria-label={label} className={cn(styles['group'], className)}>
        {children}
      </div>
    </Ctx.Provider>
  )
}

export interface RadioCardProps extends Omit<
  InputHTMLAttributes<HTMLInputElement>,
  'name' | 'value' | 'title'
> {
  value: string
  title: ReactNode
  description?: ReactNode
  disabled?: boolean
  hideIndicator?: boolean
}

export function RadioCard({
  value,
  title,
  description,
  disabled,
  hideIndicator,
  ...props
}: RadioCardProps) {
  return (
    <Ctx.Consumer>
      {(ctx) => (
        <label className={styles['card']} data-disabled={disabled || undefined}>
          <input
            type="radio"
            className={styles['input']}
            name={ctx.name}
            value={value}
            disabled={disabled}
            {...(ctx.value !== undefined
              ? { checked: ctx.value === value, onChange: () => ctx.onValueChange?.(value) }
              : {
                  defaultChecked: ctx.defaultValue === value,
                  onChange: () => ctx.onValueChange?.(value),
                })}
            {...props}
          />
          {!hideIndicator && <span className={styles['glyph']} aria-hidden="true" />}
          <span className={styles['body']}>
            <span className={styles['title']}>{title}</span>
            {description && <span className={styles['description']}>{description}</span>}
          </span>
        </label>
      )}
    </Ctx.Consumer>
  )
}

@layer cascivo.component {
  .group {
    display: grid;
    gap: var(--cascivo-space-3);
  }

  .card {
    display: flex;
    gap: var(--cascivo-space-3);
    align-items: flex-start;
    padding: var(--cascivo-space-4);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-surface);
    background: var(--cascivo-color-bg);
    cursor: pointer;
    transition:
      border-color 120ms ease,
      background-color 120ms ease;
  }

  .card:hover:not([data-disabled]) {
    border-color: var(--cascivo-color-border-strong);
  }

  .card:has(input:checked) {
    border-color: var(--cascivo-color-accent);
    background: color-mix(in oklch, var(--cascivo-color-accent) 4%, var(--cascivo-color-bg));
  }

  .card:has(input:focus-visible) {
    box-shadow: var(--cascivo-focus-ring);
  }

  .card[data-disabled] {
    opacity: 0.5;
    cursor: not-allowed;
  }

  .input {
    position: absolute;
    inline-size: 1px;
    block-size: 1px;
    overflow: hidden;
    clip-path: inset(50%);
    white-space: nowrap;
  }

  .glyph {
    flex: none;
    inline-size: 1rem;
    block-size: 1rem;
    margin-block-start: 2px;
    border: 1px solid var(--cascivo-color-border-strong);
    border-radius: var(--cascivo-radius-full);
    transition:
      border-color 120ms ease,
      background-color 120ms ease;
  }

  .card:has(input:checked) .glyph {
    border-color: var(--cascivo-color-accent);
    background: radial-gradient(circle, var(--cascivo-color-accent) 0 35%, transparent 40%);
  }

  .body {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-1);
  }

  .title {
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-medium);
    color: var(--cascivo-color-text);
  }

  .description {
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-subtle);
  }
}
